import historicalFill from './browser/fixtures/historical-baseline-fill.scene.json'
import historicalOutline from './browser/fixtures/historical-baseline-outline.scene.json'

export const HISTORICAL_BASELINE_INVENTORY = Object.freeze({
  hills: 10,
  blades: 400,
  primitives: 410,
  points: 14_540,
  hiddenLineWorkUnits: 11_584_278,
  issueRecordedHiddenLineWorkUnits: 11_372_294,
})

export function replayHistoricalBaselineFill() {
  return structuredClone(historicalFill)
}

export function replayHistoricalBaselineOutline() {
  return structuredClone(historicalOutline)
}
